    summary: { points: ["Cash flow ≠ profit — timing matters", "Invoice quickly, negotiate terms, control inventory", "Keep 2-3 months operating expenses in reserve", "The cash gap (pay suppliers before customers pay you) kills startups"], quote: { text: "Never take your eyes off the cash flow because it's the lifeblood of business.", author: "Richard Branson" } },
